using Microsoft.ML;
using Microsoft.ML.Data;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(app.Environment.ContentRootPath, "Data", "customers.csv");
ITransformer? trainedModel = null;
PredictionEngine<ChurnInput, ChurnPrediction>? predictionEngine = null;

app.MapPost("/train", () =>
{
    // Load CSV manually so we can map "Yes"/"No" to a boolean label
    var rows = File.ReadAllLines(dataPath)
        .Skip(1)
        .Where(l => !string.IsNullOrWhiteSpace(l))
        .Select(line =>
        {
            var cols = line.Split(',');
            return new ChurnInput
            {
                Age = float.Parse(cols[0]),
                Income = float.Parse(cols[1]),
                Region = cols[2].Trim(),
                PurchaseHistory = float.Parse(cols[3]),
                Label = cols[4].Trim().Equals("Yes", StringComparison.OrdinalIgnoreCase)
            };
        })
        .ToList();

    var dataView = mlContext.Data.LoadFromEnumerable(rows);

    var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region))
        .Append(mlContext.Transforms.Concatenate("Features",
            nameof(ChurnInput.Age),
            nameof(ChurnInput.Income),
            nameof(ChurnInput.PurchaseHistory),
            "RegionEncoded"))
        .Append(mlContext.BinaryClassification.Trainers.LbfgsLogisticRegression(
            labelColumnName: "Label", featureColumnName: "Features"));

    trainedModel = pipeline.Fit(dataView);
    predictionEngine = mlContext.Model.CreatePredictionEngine<ChurnInput, ChurnPrediction>(trainedModel);

    var predictions = trainedModel.Transform(dataView);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");

    return Results.Ok(new
    {
        Message = "Model trained successfully",
        Accuracy = metrics.Accuracy,
        AUC = metrics.AreaUnderRocCurve,
        F1Score = metrics.F1Score
    });
});

app.MapPost("/predict", (CustomerPredictRequest req) =>
{
    if (predictionEngine is null)
        return Results.BadRequest(new { Error = "Model not trained yet. Call POST /train first." });

    var input = new ChurnInput
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };

    var result = predictionEngine.Predict(input);
    return Results.Ok(new
    {
        WillChurn = result.PredictedLabel,
        Confidence = result.Probability
    });
});

app.MapGet("/", () => "ChurnPredictor API — POST /train then POST /predict");

app.Run();

// --- Models ---

public class ChurnInput
{
    public float Age { get; set; }
    public float Income { get; set; }
    public string Region { get; set; } = "";
    public float PurchaseHistory { get; set; }
    public bool Label { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }
